class Solution {
public:
    int maxChunksToSorted(vector<int>& nums) {
        map<int,int> need, have;
        int ans=0, curMax=-1;
        for(int x:nums){
            need[x]++; have[x]++; curMax=max(curMax,x);
            bool ok=true;
            for(int v=0;v<=curMax;v++) if(have[v]<need[v]){ ok=false; break; }
            if(ok){ ans++; for(int v=0;v<=curMax;v++) have[v]=0; curMax=-1; }
        }
        return ans;
    }
};

